const allItems = $input.all();

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenGuids) {
  staticData.seenGuids = [];
}

const seenGuids = new Set(staticData.seenGuids);

// Group new items by source
const bySource = {};

for (const item of allItems) {
  const guid = item.json.guid || item.json.id || item.json.link;
  if (!guid || seenGuids.has(guid)) continue;

  // Skip selfh.st items older than 4 weeks
  const pubDate = item.json.pubDate || item.json.isoDate || '';
  if (pubDate && item.json.link?.includes('selfh.st')) {
    const itemDate = new Date(pubDate);
    const fourWeeksAgo = new Date(Date.now() - 28 * 24 * 60 * 60 * 1000);
    if (itemDate < fourWeeksAgo) continue;
  }

  seenGuids.add(guid);

  let source = 'selfh.st';
  if (item.json.link?.includes('discourse.nixos.org')) {
    source = 'NixOS Discourse';
  } else if (item.json.link?.includes('selfh.st')) {
    source = 'selfh.st';
  }

  const title = (item.json.title || 'No title').substring(0, 100);
  const link = item.json.link || '';

  if (!bySource[source]) {
    bySource[source] = [];
  }
  bySource[source].push({ title, link });
}

const guidsArray = Array.from(seenGuids);
staticData.seenGuids = guidsArray.slice(-500);

const sources = Object.keys(bySource);
if (sources.length === 0) {
  return [];
}

// Build one embed per source, max 10 items each
const embeds = [];
for (const source of sources) {
  const items = bySource[source].slice(0, 10);
  const lines = items.map(i => `[${i.title}](${i.link})`).join('\n');
  const extra = bySource[source].length > 10 ? `\n...and ${bySource[source].length - 10} more` : '';

  embeds.push({
    title: `${source} (${bySource[source].length} new)`,
    description: lines + extra,
    color: source === 'selfh.st' ? 3447003 : 7506394
  });
}

// Discord allows max 10 embeds per message
return [{ json: { embeds: embeds.slice(0, 10) } }];
